var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두 시간 뒤면 목적지에 도착할 걸세.","JPN":"２時間後には目的地に到着するだろう。","ENG":"We'll arrive at our destination in two hours.","TWN":"預計兩小時後到達目的地。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양도 물 한 잔하겠나?","JPN":"クリス君も水を飲むかい？","ENG":"Would you like a glass of water, Chris?","TWN":"克莉絲要不要也喝杯水？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 감사합니다.","JPN":"あ、ありがとうございます。","ENG":"Oh, thank you.","TWN":"啊，非常感謝。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 나에게 개인적으로 하고 싶다는 말이 뭐지?","JPN":"それで、私に個人的に話したいということは何だね。","ENG":"So, what is it that you wanted to talk to me in private about?","TWN":"所以你想和我單獨說什麼？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흠 흠… 저, 그러니까.","JPN":"ゴホン、ゴホン……あの、えっと。","ENG":"Ahem... Well...","TWN":"咳咳……這個嘛。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우선, 저희를 구해주셔서 감사드려요.","JPN":"まず、助けてくださりありがとうございました。","ENG":"First of all, thank you for saving us.","TWN":"首先，謝謝你救了我們。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그리고 염치없지만… 한 가지 묻고 싶은 게 있어서요.","JPN":"そして失礼ですが……一つ聞きたいことがあります。","ENG":"And although I might be stepping out of bounds... there's something I want to ask you.","TWN":"我有一件事想問……雖然很不要臉。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"실은 아까 침식체와 나누는 대화를 들었거든요. 데모고르곤에 관한 이야기.","JPN":"実は、さっき侵食体との会話を聞いていました。デモゴルゴンについての話。","ENG":"You see, I overheard your talk with the C.O. earlier. About the Demogorgon.","TWN":"我剛剛聽到了你和侵蝕體的對話，就是關於魔神的話。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"귀가 밝은 친구로군.","JPN":"耳がとても良いみたいだね。","ENG":"Don't you have keen ears.","TWN":"耳朵可真靈。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"처음엔 우연히 마주쳐서 도움을 받았다고 생각했지만… 당신이 레아 씨의 정체를 얘기하는 걸 듣고도 어떻게 모른 척할 수 있겠어요?","JPN":"最初は偶然出会い、助けてもらったと思っていましたけど...…あなたがレアさんの正体について話していることを聞いたら、知らないふりはできませんでした。","ENG":"I thought it was just a coincidence that you helped us at first, but... I couldn't act dumb after hearing you talk about Leah's identity.","TWN":"一開始只是以為偶然遇到你並得到了幫助……但聽到你提及蕾亞的真實身分後，我實在按耐不住好奇心。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가장 먼저, 우리의 만남은 우연이 맞다네.","JPN":"まず、私たちの出会いは偶然であっている。","ENG":"Firstly, our encounter is purely coincidental.","TWN":"首先，我們會遇到確實是偶然。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 레아 양에 관한 정보라면 얼마 전 세간을 떠들썩하게 했던 타나베린 사건에 대해 내 부하가 전해준 보고서를 읽었거든.","JPN":"そして、レア君に関する情報ならこの前騒ぎになったタナベリン事件に関する報告書を読んだからだ。","ENG":"Also, I know about Leah because I read the report my employee gave me about the Tanaberin incident that was recently in the news.","TWN":"至於蕾亞的情報，是從我的員工給我的一份報告書上看到的。是關於之前轟動一時的達那貝林事件的報告書。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라를 통해 자네에게 맡긴 얼터니움이 다행히 제 역할을 해준 것 같더군.","JPN":"リュドミラを通じて君たちに預けたオルタニウムがちゃんと役割を果たしたようだね。","ENG":"Fortunately, the Alternium I left you through Lyudmila did its job.","TWN":"看來，我請盧德米拉轉交給你的黑化永恆之金發揮了作用。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아앗!","JPN":"ああっ！","ENG":"Oh!","TWN":"啊啊！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 당신이 류드밀라 씨가 주셨던 그 보석의 주인인 건가요?!","JPN":"それじゃ、あなたがリュドミラさんが渡した宝石の持ち主なんですか！？","ENG":"Then you're the owner of the gem that Lyudmila gave me?!","TWN":"你就是盧德米拉給我的那顆寶石的主人？！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};